[CmdletBinding(SupportsShouldProcess=$true)]
param([switch]$ClearTemp,[switch]$ClearWindowsUpdateCache,[switch]$RunComponentCleanup,[switch]$RunCheckDiskScan,[int]$OlderThanDays=7,[string]$OutputPath="$env:USERPROFILE\Desktop\DiskStorageRepair")
$ErrorActionPreference='Stop';New-Item -ItemType Directory -Path $OutputPath -Force|Out-Null;$Log=Join-Path $OutputPath ("repair-{0:yyyyMMdd-HHmmss}.log"-f(Get-Date));function L($m){"$(Get-Date -Format s) $m"|Tee-Object -FilePath $Log -Append};if(-not($ClearTemp-or$ClearWindowsUpdateCache-or$RunComponentCleanup-or$RunCheckDiskScan)){throw'Choose at least one repair action.'}
Get-Volume|Select DriveLetter,FileSystemLabel,FileSystem,Size,SizeRemaining,HealthStatus|Export-Csv (Join-Path $OutputPath 'before.csv') -NoTypeInformation
if($ClearTemp){$cut=(Get-Date).AddDays(-$OlderThanDays);foreach($root in @($env:TEMP,"$env:WINDIR\Temp")){if(Test-Path $root){Get-ChildItem $root -Force -ErrorAction SilentlyContinue|Where-Object LastWriteTime-lt$cut|ForEach-Object{if($PSCmdlet.ShouldProcess($_.FullName,'Remove stale temporary item')){Remove-Item $_.FullName -Recurse -Force -ErrorAction SilentlyContinue}}}};L'Temporary cleanup completed.'}
if($ClearWindowsUpdateCache){if($PSCmdlet.ShouldProcess('Windows Update cache','Stop services and clear download cache')){Stop-Service wuauserv,bits -Force -ErrorAction SilentlyContinue;Remove-Item "$env:WINDIR\SoftwareDistribution\Download\*" -Recurse -Force -ErrorAction SilentlyContinue;Start-Service bits,wuauserv -ErrorAction SilentlyContinue;L'Windows Update download cache cleared.'}}
if($RunComponentCleanup-and$PSCmdlet.ShouldProcess('Windows component store','Run component cleanup')){dism /Online /Cleanup-Image /StartComponentCleanup|Tee-Object -FilePath $Log -Append;L'Component cleanup completed.'}
if($RunCheckDiskScan-and$PSCmdlet.ShouldProcess('System drive','Run online CHKDSK scan')){chkdsk $env:SystemDrive /scan|Tee-Object -FilePath $Log -Append;L'CHKDSK scan completed.'}
Get-Volume|Select DriveLetter,Size,SizeRemaining,HealthStatus|Export-Csv (Join-Path $OutputPath 'after.csv') -NoTypeInformation;L'Repair workflow finished.'